class TransactionValidator:
    REQUIRED_FIELDS = {'transaction_id', 'type', 'amount', 'currency', 'timestamp'}
    VALID_TRANSACTION_TYPES = {
        'payment', 'refund', 'transfer', 'withdrawal',
        'deposit', 'fraud_check', 'balance_inquiry', 'fee_calculation'
    }
    VALID_CURRENCIES = {'USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD', 'CHF'}
    MAX_AMOUNT = 1_000_000.00
    MIN_AMOUNT = 0.01

    @classmethod
    def validate(cls, transaction: Dict[str, Any]) -> bool:
        missing = cls.REQUIRED_FIELDS - set(transaction.keys())
        if missing:
            raise TransactionValidationError(f"Missing required fields: {missing}")

        if transaction['type'] not in cls.VALID_TRANSACTION_TYPES:
            raise TransactionValidationError(
                f"Invalid transaction type: {transaction['type']}. "
                f"Must be one of {cls.VALID_TRANSACTION_TYPES}"
            )

        try:
            amount = float(transaction['amount'])
        except (ValueError, TypeError):
            raise TransactionValidationError(f"Invalid amount: {transaction['amount']}")

        if amount < cls.MIN_AMOUNT or amount > cls.MAX_AMOUNT:
            raise TransactionValidationError(
                f"Amount {amount} out of range [{cls.MIN_AMOUNT}, {cls.MAX_AMOUNT}]"
            )

        if transaction['currency'] not in cls.VALID_CURRENCIES:
            raise TransactionValidationError(
                f"Invalid currency: {transaction['currency']}. "
                f"Must be one of {cls.VALID_CURRENCIES}"
            )

        if not isinstance(transaction.get('transaction_id'), str) or len(transaction['transaction_id']) > 128:
            raise TransactionValidationError("Invalid transaction_id format")

        return True


class MessageIntegrityChecker:
    @staticmethod
    def compute_hmac(message_bytes: bytes) -> str:
        return hmac.new(HMAC_SECRET_KEY, message_bytes, hashlib.sha256).hexdigest()

    @staticmethod
    def verify_hmac(message_bytes: bytes, expected_hmac: str) -> bool:
        computed = hmac.new(HMAC_SECRET_KEY, message_bytes, hashlib.sha256).hexdigest()
        return hmac.compare_digest(computed, expected_hmac)


def process_payment(transaction: Dict[str, Any]) -> Dict[str, Any]:
    logger.info(f"Processing payment: {transaction['transaction_id']} - "
                f"Amount: {transaction['amount']} {transaction['currency']}")

    if float(transaction['amount']) > 10000:
        return {
            'status': 'pending_review',
            'transaction_id': transaction['transaction_id'],
            'reason': 'High value transaction requires manual review',
            'processed_at': datetime.now(timezone.utc).isoformat()
        }

    return {
        'status': 'completed',
        'transaction_id': transaction['transaction_id'],
        'amount_processed': transaction['amount'],
        'currency': transaction['currency'],
        'processed_at': datetime.now(timezone.utc).isoformat()
    }


