def process_fraud_check(transaction: Dict[str, Any]) -> Dict[str, Any]:
    logger.info(f"Processing fraud check: {transaction['transaction_id']}")
    risk_score = 0.0
    amount = float(transaction['amount'])

    if amount > 5000:
        risk_score += 0.3
    if transaction.get('country') and transaction['country'] != transaction.get('account_country'):
        risk_score += 0.4
    if transaction.get('is_first_transaction', False):
        risk_score += 0.2

    is_fraudulent = risk_score > 0.7

    return {
        'status': 'flagged' if is_fraudulent else 'cleared',
        'transaction_id': transaction['transaction_id'],
        'risk_score': risk_score,
        'is_fraudulent': is_fraudulent,
        'processed_at': datetime.now(timezone.utc).isoformat()
    }


