class SafeHandlerResolver:
    """Resolves handler names to callable functions with strict whitelisting."""

    @staticmethod
    def resolve(handler_name: str) -> Callable:
        if handler_name not in ALLOWED_HANDLERS:
            raise HandlerNotAllowedError(
                f"Handler '{handler_name}' is not in the allowed handlers list. "
                f"Allowed: {ALLOWED_HANDLERS}"
            )

        if handler_name in BUILTIN_HANDLERS:
            return BUILTIN_HANDLERS[handler_name]

        raise HandlerNotAllowedError(f"Handler '{handler_name}' not found in built-in handlers")

    @staticmethod
    def resolve_from_module(module_name: str, handler_name: str) -> Callable:
        if module_name not in ALLOWED_HANDLER_MODULES:
            raise HandlerNotAllowedError(
                f"Module '{module_name}' is not in the allowed modules list. "
                f"Allowed: {ALLOWED_HANDLER_MODULES}"
            )

        if handler_name not in ALLOWED_HANDLERS:
            raise HandlerNotAllowedError(
                f"Handler '{handler_name}' is not in the allowed handlers list. "
                f"Allowed: {ALLOWED_HANDLERS}"
            )

        try:
            module = importlib.import_module(module_name)
            handler = getattr(module, handler_name)
            if not callable(handler):
                raise HandlerNotAllowedError(f"'{handler_name}' in module '{module_name}' is not callable")
            return handler
        except (ImportError, AttributeError) as e:
            raise HandlerNotAllowedError(f"Cannot resolve handler: {e}")


class TransactionProcessor:
    def __init__(self):
        self.handler_resolver = SafeHandlerResolver()
        self.processed_count = 0
        self.error_count = 0
        self.results = []

    def process_message(self, message_value: bytes, message_headers: Optional[list] = None) -> Dict[str, Any]:
        try:
            transaction = self._deserialize_message(message_value, message_headers)
        except (json.JSONDecodeError, MessageIntegrityError) as e:
            self.error_count += 1
            logger.error(f"Failed to deserialize message: {e}")
            return {'status': 'error', 'reason': f'Deserialization failed: {e}'}

        try:
            TransactionValidator.validate(transaction)
        except TransactionValidationError as e:
            self.error_count += 1
            logger.error(f"Transaction validation failed: {e}")
            return {
                'status': 'validation_error',
                'reason': str(e),
                'transaction_id': transaction.get('transaction_id', 'unknown')
            }

        handler_name = self._resolve_handler_name(transaction)

        try:
            handler = self.handler_resolver.resolve(handler_name)
        except HandlerNotAllowedError as e:
            self.error_count += 1
            logger.error(f"Handler resolution failed: {e}")
            return {
                'status': 'handler_error',
                'reason': str(e),
                'transaction_id': transaction.get('transaction_id', 'unknown')
            }

        try:
            result = handler(transaction)
            self.processed_count += 1
            self.results.append(result)
            logger.info(f"Transaction {transaction['transaction_id']} processed successfully: {result['status']}")
            return result
        except Exception as e:
            self.error_count += 1
            logger.error(f"Handler execution failed for {transaction.get('transaction_id', 'unknown')}: {e}")
            return {
                'status': 'processing_error',
                'reason': str(e),
                'transaction_id': transaction.get('transaction_id', 'unknown')
            }

    def _deserialize_message(self, message_value: bytes, message_headers: Optional[list] = None) -> Dict[str, Any]:
        headers_dict = {}
        if message_headers:
            for key, value in message_headers:
                if isinstance(value, bytes):
                    headers_dict[key] = value.decode('utf-8')
                else:
                    headers_dict[key] = value

        content_type = headers_dict.get('content-type', 'application/json')

        if content_type == 'application/json':
            if 'hmac-sha256' in headers_dict:
                if not MessageIntegrityChecker.verify_hmac(message_value, headers_dict['hmac-sha256']):
                    raise MessageIntegrityError("HMAC verification failed - message may have been tampered with")

            transaction = json.loads(message_value.decode('utf-8'))
            if not isinstance(transaction, dict):
                raise TransactionValidationError("Deserialized message is not a dictionary")
            return transaction
        else:
            raise TransactionValidationError(
                f"Unsupported content type: {content_type}. Only 'application/json' is supported. "
                f"Arbitrary object deserialization (pickle, etc.) is disabled for security."
            )

    def _resolve_handler_name(self, transaction: Dict[str, Any]) -> str:
        explicit_handler = transaction.get('handler')
        if explicit_handler:
            if explicit_handler not in ALLOWED_HANDLERS:
                raise HandlerNotAllowedError(
                    f"Explicitly specified handler '{explicit_handler}' is not allowed"
                )
            return explicit_handler

        transaction_type = transaction.get('type', '')
        handler_name = TRANSACTION_TYPE_TO_HANDLER.get(transaction_type)
        if not handler_name:
            raise HandlerNotAllowedError(
                f"No handler mapping for transaction type '{transaction_type}'"
            )
        return handler_name

    def get_stats(self) -> Dict[str, Any]:
        return {
            'processed_count': self.processed_count,
            'error_count': self.error_count,
            'total_messages': self.processed_count + self.error_count
        }


class FinancialTransactionConsumer:
    def __init__(
        self,
        bootstrap_servers: str = 'localhost:9092',
        topics: Optional[list] = None,
        group_id: str = 'financial-transaction-processor',
        auto_offset_reset: str = 'earliest',
        enable_auto_commit: bool = False,
        max_poll_records: int = 100,
        consumer_timeout_ms: int = -1,
        security_protocol: str = 'PLAINTEXT',
        sasl_mechanism: Optional[str] = None,
        sasl_plain_username: Optional[str] = None,
        sasl_plain_password: Optional[str] = None,
    ):
        self.topics = topics or ['financial-transactions']
        self.processor = TransactionProcessor()
        self.running = False

        consumer_config = {
            'bootstrap_servers': bootstrap_servers,
            'group_id': group_id,
            'auto_offset_reset': auto_offset_reset,
            'enable_auto_commit': enable_auto_commit,
            'max_poll_records': max_poll_records,
            'value_deserializer': None,
            'security_protocol': security_protocol,
        }

        if consumer_timeout_ms > 0:
            consumer_config['consumer_timeout_ms'] = consumer_timeout_ms

        if sasl_mechanism:
            consumer_config['sasl_mechanism'] = sasl_mechanism
            consumer_config['sasl_plain_username'] = sasl_plain_username
            consumer_config['sasl_plain_password'] = sasl_plain_password

        try:
            self.consumer = KafkaConsumer(**consumer_config)
            self.consumer.subscribe(self.topics)
            logger.info(f"Kafka consumer initialized. Subscribed to topics: {self.topics}")
        except KafkaError as e:
            logger.error(f"Failed to initialize Kafka consumer: {e}")
            raise

    def start(self):
        self.running = True
        logger.info("Starting financial transaction consumer...")

        try:
            while self.running:
                message_batch = self.consumer.poll(timeout_ms=1000)

                for topic_partition, messages in message_batch.items():
                    for message in messages:
                        try:
                            logger.info(
                                f"Received message from {message.topic} "
                                f"partition={message.partition} "
                                f"offset={message.offset}"
                            )

                            result = self.processor.process_message(
                                message.value,
                                message.headers
                            )

                            if result.get('status') not in ('error', 'validation_error',
                                                              'handler_error', 'processing_error'):
                                self.consumer.commit()
                                logger.info(
                                    f"Committed offset {message.offset} for "
                                    f"{message.topic}-{message.partition}"
                                )
                            else:
                                logger.warning(
                                    f"Message processing resulted in error status: {result.get('status')}. "
                                    f"Transaction: {result.get('transaction_id', 'unknown')}. "
                                    f"Reason: {result.get('reason', 'unknown')}"
                                )
                                self._handle_failed_message(message, result)
                                self.consumer.commit()

                        except Exception as e:
                            logger.error(f"Unexpected error processing message: {e}", exc_info=True)
                            self._handle_failed_message(message, {'reason': str(e)})
                            self.consumer.commit()

                stats = self.processor.get_stats()
                if stats['total_messages'] > 0 and stats['total_messages'] % 100 == 0:
                    logger.info(f"Processing stats: {stats}")

        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
        except KafkaError as e:
            logger.error(f"Kafka error: {e}", exc_info=True)
        finally:
            self.stop()

    def stop(self):
        self.running = False
        if hasattr(self, 'consumer'):
            self.consumer.close()
            logger.info("Kafka consumer closed")
        stats = self.processor.get_stats()
        logger.info(f"Final processing stats: {stats}")

    def _handle_failed_message(self, message, error_info: Dict[str, Any]):
        logger.error(
            f"Failed message - Topic: {message.topic}, "
            f"Partition: {message.partition}, "
            f"Offset: {message.offset}, "
            f"Error: {error_info.get('reason', 'unknown')}"
        )


class TransactionMessageProducer:
    """Utility to create properly formatted and signed transaction messages."""

    @staticmethod
    def create_message(transaction: Dict[str, Any]) -> tuple:
        message_bytes = json.dumps(transaction).encode('utf-8')
        message_hmac = MessageIntegrityChecker.compute_hmac(message_bytes)

        headers = [
            ('content-type', b'application/json'),
            ('hmac-sha256', message_hmac.encode('utf-8')),
            ('produced-at', datetime.now(timezone.utc).isoformat().encode('utf-8')),
        ]

        return message_bytes, headers


